using System.Text;

namespace Pekspro.DataAnnotationValuesExtractor;

public static class SourceGenerationHelper
{
    private const string Header = @"//---------------------------------------------------------------------------------------
// <auto-generated>
//     This code was generated by the Pekspro.DataAnnotationValuesExtractor source generator.
//
//     Changes to this file may cause incorrect behavior and will be lost if
//     the code is regenerated.
// </auto-generated>
//---------------------------------------------------------------------------------------
";

    public static string GenerateExtensionClass(in DataAnnotationValuesDetailedOptions options)
    {
        StringBuilder sb = new StringBuilder();
        
        sb.Append(Header);

        bool added = false;

        if (options.Types != null && options.Types.Length > 0)
        {
            added = AddDataAnnotationValuesAsPartialClasses(sb, options);
        }

        if (!added)
        {
            // Generate an empty partial class for the configuration class
            AddEmptyConfigurationClass(sb, options);
        }

        return sb.ToString();
    }

    private static bool AddDataAnnotationValuesAsPartialClasses(StringBuilder sb, in DataAnnotationValuesDetailedOptions options)
    {
        bool added = false;

        if (options.Types == null || options.Types.IsDefault)
            return false;

        // Group types by namespace
        var typesByNamespace = options.Types
            .GroupBy(t => string.IsNullOrEmpty(t.Namespace) ? string.Empty : t.Namespace)
            .OrderBy(g => g.Key);

        foreach (var namespaceGroup in typesByNamespace)
        {
            if (added)
            {
                sb.AppendLine();
            }

            string currentNamespace = namespaceGroup.Key;
            
            // Add namespace declaration if not global
            if (!string.IsNullOrEmpty(currentNamespace))
            {
                sb.Append(@"
namespace ").Append(currentNamespace).Append(@"
{");
            }

            bool firstTypeInNamespace = true;

            foreach (var typeInfo in namespaceGroup)
            {
                // Only generate if there are properties with annotations
                if (typeInfo.Properties.IsDefault || typeInfo.Properties.Length == 0)
                    continue;

                bool hasAnnotations = false;
                StringBuilder typeSb = new StringBuilder();

                foreach (var property in typeInfo.Properties)
                {
                    StringBuilder propertySb = new StringBuilder();
                    bool firstValue = true;

                    // Add StringLength values
                    if (property.StringLength.HasValue)
                    {
                        if (!firstValue)
                        {
                            propertySb.AppendLine();
                        }
                        else
                        {
                            firstValue = false;
                        }

                        var stringLength = property.StringLength.Value;
                        
                        propertySb.Append(@"
                /// <summary>
                /// Maximum length for ").Append(property.PropertyName).Append(@".
                /// </summary>
                public const int MaximumLength = ").Append(stringLength.MaximumLength).Append(";");
                        
                        propertySb.Append(@"

                /// <summary>
                /// Minimum length for ").Append(property.PropertyName).Append(@".
                /// </summary>
                public const int MinimumLength = ").Append(stringLength.MinimumLength).Append(";");
                    }

                    // Add Range values
                    if (property.Range.HasValue)
                    {
                        if (!firstValue)
                        {
                            propertySb.AppendLine();
                        }
                        else
                        {
                            firstValue = false;
                        }

                        var range = property.Range.Value;
                        
                        propertySb.Append(@"
                /// <summary>
                /// Minimum value for ").Append(property.PropertyName).Append(@".
                /// </summary>
                public const ").Append(range.TypeName).Append(" Minimum = ").Append(range.Minimum).Append(";");
                        
                        propertySb.Append(@"

                /// <summary>
                /// Maximum value for ").Append(property.PropertyName).Append(@".
                /// </summary>
                public const ").Append(range.TypeName).Append(" Maximum = ").Append(range.Maximum).Append(";");
                        
                        propertySb.Append(@"

                /// <summary>
                /// Indicates whether the minimum value for ").Append(property.PropertyName).Append(@" is exclusive.
                /// </summary>
                public const bool MinimumIsExclusive = ").Append(range.MinimumIsExclusive ? "true" : "false").Append(";");
                        
                        propertySb.Append(@"

                /// <summary>
                /// Indicates whether the maximum value for ").Append(property.PropertyName).Append(@" is exclusive.
                /// </summary>
                public const bool MaximumIsExclusive = ").Append(range.MaximumIsExclusive ? "true" : "false").Append(";");
                    }

                    // Add Required values
                    if (options.AddRequired)
                    {
                        if (!firstValue)
                        {
                            propertySb.AppendLine();
                        }
                        else
                        {
                            firstValue = false;
                        }

                        propertySb.Append(@"
                /// <summary>
                /// Indicates whether ").Append(property.PropertyName).Append(@" is required.
                /// </summary>
                public const bool IsRequired = ").Append(property.IsRequired ? "true" : "false").Append(";");
                    }

                    if (propertySb.Length > 0)
                    {
                        if (hasAnnotations)
                        {
                            typeSb.AppendLine();
                        }

                        hasAnnotations = true;
                        
                        // Add the property wrapper
                        typeSb.Append(@"
            /// <summary>
            /// Data annotation values for ").Append(property.PropertyName).Append(@".
            /// </summary>
            public static class ").Append(property.PropertyName).Append(@"
            {");
                        typeSb.Append(propertySb);
                        typeSb.Append(@"
            }");
                    }
                }

                if (hasAnnotations)
                {
                    if (!firstTypeInNamespace)
                    {
                        sb.AppendLine();
                    }
                    else
                    {
                        firstTypeInNamespace = false;
                    }


                    added = true;
                    
                    // Add the partial class declaration
                    sb.Append(@"
    /// <summary>
    /// Data annotation values for ").Append(typeInfo.TypeName).Append(@".
    /// </summary>
    [global::System.CodeDom.Compiler.GeneratedCodeAttribute(""Pekspro.DataAnnotationValuesExtractor"", """).Append(Constants.Version).Append(@""")]
    public partial class ").Append(typeInfo.TypeName).Append(@"
    {
        /// <summary>
        /// Data annotation values.
        /// </summary>
        public static class Annotations
        {");
                    sb.Append(typeSb);
                    sb.Append(@"
        }
    }");
                }
            }

            // Close namespace if needed
            if (!string.IsNullOrEmpty(currentNamespace))
            {
                sb.Append(@"
}");
            }
        }

        return added;
    }

    private static void AddEmptyConfigurationClass(StringBuilder sb, in DataAnnotationValuesDetailedOptions options)
    {
        if (!string.IsNullOrEmpty(options.Namespace))
        {
            sb.Append(@"
namespace ").Append(options.Namespace).Append(@"
{");
        }

        sb.Append(@"

    /// <summary>
    /// Configuration for data annotation values generation.
    /// </summary>
    [global::System.CodeDom.Compiler.GeneratedCodeAttribute(""Pekspro.DataAnnotationValuesExtractor"", """).Append(Constants.Version).Append(@""")]
    partial class ").Append(options.Name).Append(@"
    {
#warning No data annotation values were generated. Ensure the types specified have properties with data annotations.
    }");

        if (!string.IsNullOrEmpty(options.Namespace))
        {
            sb.Append(@"
}");
        }
    }
}

